def merge_sorted(a: list, b: list) -> list:
    result = []
    i = j = 0
    while i < len(a) and j < len(b):
        if a[i] <= b[j]:
            result.append(a[i])
            i += 1
        else:
            result.append(b[j])
            j += 1
    result.extend(a[i:])
    result.extend(b[j:])
    return result


class TestMergeSortedHappyPath:
    """Tests for typical, well-formed inputs."""

    def test_two_equal_length_sorted_lists(self):
        assert merge_sorted([1, 3, 5], [2, 4, 6]) == [1, 2, 3, 4, 5, 6]

    def test_already_interleaved(self):
        assert merge_sorted([1, 4, 7], [2, 5, 8]) == [1, 2, 4, 5, 7, 8]

    def test_a_entirely_before_b(self):
        assert merge_sorted([1, 2, 3], [4, 5, 6]) == [1, 2, 3, 4, 5, 6]

    def test_b_entirely_before_a(self):
        assert merge_sorted([7, 8, 9], [1, 2, 3]) == [1, 2, 3, 7, 8, 9]

    def test_different_lengths_a_longer(self):
        assert merge_sorted([1, 2, 3, 4, 5], [3, 6]) == [1, 2, 3, 3, 4, 5, 6]

    def test_different_lengths_b_longer(self):
        assert merge_sorted([2], [1, 3, 4, 5, 6]) == [1, 2, 3, 4, 5, 6]

    def test_with_negative_numbers(self):
        assert merge_sorted([-5, -2, 0], [-3, 1, 4]) == [-5, -3, -2, 0, 1, 4]

    def test_with_floats(self):
        assert merge_sorted([1.1, 2.2], [1.5, 3.3]) == [1.1, 1.5, 2.2, 3.3]

    def test_with_strings(self):
        assert merge_sorted(["apple", "cherry"], ["banana", "date"]) == [
            "apple",
            "banana",
            "cherry",
            "date",
        ]


