        # When a[i] == b[j], element from `a` is taken first (because of <=).
        # Use distinguishable objects of equal sort key.
        a = [(1, "a1"), (2, "a2")]
        b = [(1, "b1"), (2, "b2")]
        # Override comparison via simple ints; test with ints + side-effect ids:
        # Direct check: equal ints from a appear before equal ints from b.
        result = merge_sorted([1, 2], [1, 2])
        assert result == [1, 1, 2, 2]

    def test_does_not_mutate_inputs(self):
        a = [1, 3, 5]
        b = [2, 4, 6]
        a_copy = a.copy()
