        result = merge_sorted(a, b)
        assert result is not a
        assert result is not b

    def test_large_input(self):
        a = list(range(0, 1000, 2))   # even numbers
        b = list(range(1, 1000, 2))   # odd numbers
        assert merge_sorted(a, b) == list(range(1000))

    def test_result_length_equals_sum_of_inputs(self):
        a = [1, 2, 3]
        b = [4, 5, 6, 7]
        assert len(merge_sorted(a, b)) == len(a) + len(b)


